{
  "mode": "method",
  "tests": [
    {
      "name": "valid_registration",
      "input": ["user123", "password123"],
      "output": true,
      "args": ["user123", "password123"],
      "notes": "Tests a valid registration scenario."
    },
    {
      "name": "duplicate_registration",
      "input": ["user123", "password123"],
      "output": false,
      "args": ["user123", "password123"],
      "notes": "Tests registration with an already registered username."
    },
    {
      "name": "empty_username",
      "input": ["", "password123"],
      "output": false,
      "args": ["", "password123"],
      "notes": "Tests registration with an empty username."
    },
    {
      "name": "empty_password",
      "input": ["user123", ""],
      "output": false,
      "args": ["user123", ""],
      "notes": "Tests registration with an empty password."
    },
    {
      "name": "short_username",
      "input": ["us", "password123"],
      "output": false,
      "args": ["us", "password123"],
      "notes": "Tests registration with a username that is too short."
    },
    {
      "name": "short_password",
      "input": ["user123", "pass"],
      "output": false,
      "args": ["user123", "pass"],
      "notes": "Tests registration with a password that is too short."
    },
    {
      "name": "special_characters_in_username",
      "input": ["user@123", "password123"],
      "output": false,
      "args": ["user@123", "password123"],
      "notes": "Tests registration with special characters in the username."
    },
    {
      "name": "long_username",
      "input": ["user12345678901234567890", "password123"],
      "output": false,
      "args": ["user12345678901234567890", "password123"],
      "notes": "Tests registration with a username that is too long."
    }
  ],
  "assumptions": "Usernames must be between 3 and 20 characters, passwords must be at least 8 characters.",
  "notes": "Ensure to validate edge cases for registration."
}
